  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"EVEN","tone":"#e8b84b","tldr":"Weather the poke — flame his Heroic Swing gap at Danger-Zone heat.","breakdown":"Akshan plays around Heroic Swing. Ride 50-100 heat, double-E slow into the flamespitter when Heroic Swing is down, and R cuts the lane in half. Doran’s Shield blunts the poke war.","dos":["Manage heat to Danger Zone","E-slow when Heroic Swing is down","Equalizer the all-in path"],"donts":["Overheat with no trade","Flame at max range only","Waste R on one man"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Overheat flame + E slow."},"win":"Flame his Heroic Swing gap at Danger-Zone heat."},
  cassiopeia: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — flame his Miasma gap at Danger-Zone heat.","breakdown":"Cassiopeia plays around Miasma. Ride 50-100 heat, double-E slow into the flamespitter when Miasma is down, and R cuts the lane in half. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Manage heat to Danger Zone","E-slow when Miasma is down","Equalizer the all-in path"],"donts":["Overheat with no trade","Flame at max range only","Waste R on one man"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Overheat flame + E slow."},"win":"Flame his Miasma gap at Danger-Zone heat."},
